'use client';

import { Check } from 'lucide-react';
import React, { useState } from 'react';

const Login = () => {
  const [loginMethod, setLoginMethod] = useState<'password' | 'otp'>('password');
  const [username, setUsername] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [otp, setOtp] = useState<string>('');
  const [showPassword, setShowPassword] = useState<boolean>(false);
  const [otpSent, setOtpSent] = useState<boolean>(false);
  const points = [
  'One click apply using naukaa profile.',
  'Get relevant job recommendations..',
  'Showcase profile to top companies and consultants.',
  'Know application status on applied jobs ekndjewlfejcnewcnewcdkjncjdckjnkjenuekcnejneicne.',
];
  const handleLogin = (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    console.log('Username:', username);
    if (loginMethod === 'password') {
      console.log('Password:', password);
    } else {
      console.log('OTP:', otp);
    }
    alert('Login clicked! Check console');
  };

  const handleSendOtp = () => {
    if (username) {
      setOtpSent(true);
      alert('OTP sent to ' + username);
    }
  };

  const handleSocialLogin = (provider: string) => {
    alert(`${provider} login clicked`);
  };

  return (
    <div className="min-h-screen bg-gray-50 flex">
      
      {/* Left Side - Platform Info & Illustration */}
      <div className="hidden lg:flex lg:w-1/2 bg-gradient-to-br from-blue-600 to-blue-800 ml-20 p-10 my-1 flex-col justify-center items-center text-white">
        
        {/* Heading */}
        <h2 className="text-4xl font-bold mb-4 text-center">New to Naukaa?</h2>

        {/* Platform Description */}        
        <div className="max-w-md mb-4 space-y-3 text-lg leading-relaxed mx-auto">
        {points.map((text, index) => (
            <p key={index} className="grid grid-cols-[20px_1fr] gap-2 text-left">
            <Check className="w-5 h-5 text-green-600 mt-1" />
            {text}
            </p>
        ))}
        </div>   
             

        {/* Illustration Image Placeholder */}
        <div className="mb-4">
          <svg className="w-60 h-60" viewBox="0 0 300 300" fill="none" xmlns="http://www.w3.org/2000/svg">
            {/* Background circle */}
            <circle cx="150" cy="150" r="120" fill="rgba(255,255,255,0.1)" />
            
            {/* Document/Resume */}
            <rect x="90" y="80" width="120" height="160" rx="8" fill="rgba(255,255,255,0.9)" />
            <rect x="105" y="100" width="90" height="8" rx="4" fill="#3B82F6" />
            <rect x="105" y="120" width="70" height="6" rx="3" fill="#93C5FD" />
            <rect x="105" y="135" width="80" height="6" rx="3" fill="#93C5FD" />
            <rect x="105" y="150" width="60" height="6" rx="3" fill="#93C5FD" />
            
            {/* Person icon */}
            <circle cx="150" cy="195" r="15" fill="#3B82F6" />
            <path d="M150 210 C130 210, 125 220, 125 230 L175 230 C175 220, 170 210, 150 210 Z" fill="#3B82F6" />
            
            {/* Checkmark */}
            <circle cx="220" cy="100" r="25" fill="#10B981" />
            <path d="M210 100 L217 107 L230 94" stroke="white" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round" fill="none" />
            
            {/* Briefcase icon */}
            <rect x="55" y="130" width="30" height="25" rx="3" fill="rgba(255,255,255,0.9)" />
            <rect x="60" y="125" width="20" height="5" rx="2" fill="rgba(255,255,255,0.9)" />
            <circle cx="70" cy="142" r="3" fill="#3B82F6" />
          </svg>
        </div>

        {/* Register Button */}
        <button className="px-10 py-2 bg-white text-blue-700 rounded-lg font-semibold hover:bg-gray-100 transition shadow-lg text-lg">
          Register Now
        </button>
      </div>

      {/* Right Side - Login Form */}
      <div className="w-full lg:w-1/2 flex items-center justify-center p-8">
        <div className="bg-white p-8 rounded-lg shadow-lg w-full max-w-md">
          
          {/* Title */}
          <h1 className="text-2xl font-bold text-center mb-6">Login</h1>

          {/* Login Method Toggle */}
          <div className="flex mb-6 bg-gray-100 rounded-lg p-1">
            <button
              type="button"
              onClick={() => setLoginMethod('password')}
              className={`flex-1 py-2 rounded-md transition ${
                loginMethod === 'password' 
                  ? 'bg-white shadow-sm font-semibold' 
                  : 'text-gray-600'
              }`}
            >
              Password
            </button>
            <button
              type="button"
              onClick={() => setLoginMethod('otp')}
              className={`flex-1 py-2 rounded-md transition ${
                loginMethod === 'otp' 
                  ? 'bg-white shadow-sm font-semibold' 
                  : 'text-gray-600'
              }`}
            >
              OTP
            </button>
          </div>

          {/* Form */}
          <form onSubmit={handleLogin}>
            
            {/* Username Field */}
            <div className="mb-4">
              <label className="block text-gray-700 mb-2">
                {loginMethod === 'otp' ? 'Mobile Number' : 'Username / Mobile'}
              </label>
              <input
                type="text"
                value={username}
                onChange={(e) => setUsername(e.target.value)}
                placeholder={loginMethod === 'otp' ? 'Enter mobile number' : 'Enter username or mobile'}
                className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
                required
              />
            </div>

            {/* Password Field */}
            {loginMethod === 'password' && (
              <div className="mb-4">
                <label className="block text-gray-700 mb-2">
                  Password
                </label>
                <div className="relative">
                  <input
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter password"
                    className="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-3 top-3 text-gray-500"
                  >
                    {showPassword ? '👁️' : '👁️‍🗨️'}
                  </button>
                </div>
              </div>
            )}

            {/* OTP Field */}
            {loginMethod === 'otp' && (
              <div className="mb-4">
                <label className="block text-gray-700 mb-2">
                  OTP
                </label>
                <div className="flex gap-2">
                  <input
                    type="text"
                    value={otp}
                    onChange={(e) => setOtp(e.target.value)}
                    placeholder="Enter OTP"
                    maxLength={6}
                    className="flex-1 px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:border-blue-500"
                    required
                    disabled={!otpSent}
                  />
                  <button
                    type="button"
                    onClick={handleSendOtp}
                    className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 whitespace-nowrap"
                  >
                    {otpSent ? 'Resend' : 'Send OTP'}
                  </button>
                </div>
              </div>
            )}

            {/* Forgot Password */}
            {loginMethod === 'password' && (
              <div className="text-right mb-4">
                <a href="#" className="text-sm text-blue-600 hover:underline">
                  Forgot Password?
                </a>
              </div>
            )}

            {/* Login Button */}
            <button
              type="submit"
              className="w-full bg-blue-600 text-white py-2 rounded-lg hover:bg-blue-700 transition"
            >
              Login
            </button>

          </form>

          {/* Divider */}
          <div className="relative my-6">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-gray-300"></div>
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-2 bg-white text-gray-500">Or continue with</span>
            </div>
          </div>

          {/* Social Login Buttons */}
          <div className="space-y-3">
            <button
              type="button"
              onClick={() => handleSocialLogin('Google')}
              className="w-full flex items-center justify-center gap-3 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition"
            >
              <svg className="w-5 h-5" viewBox="0 0 24 24">
                <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
              </svg>
              <span className="font-medium">Sign in with Google</span>
            </button>

            <button
              type="button"
              onClick={() => handleSocialLogin('Apple')}
              className="w-full flex items-center justify-center gap-3 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 transition"
            >
              <svg className="w-5 h-5" viewBox="0 0 24 24" fill="currentColor">
                <path d="M17.05 20.28c-.98.95-2.05.8-3.08.35-1.09-.46-2.09-.48-3.24 0-1.44.62-2.2.44-3.06-.35C2.79 15.25 3.51 7.59 9.05 7.31c1.35.07 2.29.74 3.08.8 1.18-.24 2.31-.93 3.57-.84 1.51.12 2.65.72 3.4 1.8-3.12 1.87-2.38 5.98.48 7.13-.57 1.5-1.31 2.99-2.54 4.09l.01-.01zM12.03 7.25c-.15-2.23 1.66-4.07 3.74-4.25.29 2.58-2.34 4.5-3.74 4.25z"/>
              </svg>
              <span className="font-medium">Sign in with Apple</span>
            </button>
          </div>

          {/* Register Link - Mobile Only */}
          <p className="text-center mt-6 text-gray-600 lg:hidden">
            Don&apos;t have an account?{' '}
            <a href="#" className="text-blue-600 hover:underline font-semibold">
              Register
            </a>
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;